import{_ as l,o as e,c as o,ag as s}from"./chunks/framework.eQLvDOR_.js";const h=JSON.parse('{"title":"Agent Skills 与 MCP 的区别及各自作用","description":"","frontmatter":{"title":"Agent Skills 与 MCP 的区别及各自作用","query":"skills有什么用，和mcp有什么区别","sources_consulted":["02_Library/ADK_Agent_Skills/[ADK_Agent_Skills] ADK-Agent-Skills-Progressive-Disclosure-with-SkillToolset-(Part-1).md","02_Library/NotebookLM_Workflows/[NotebookLM_Workflows] Integrate-NotebookLM-with-Gemini-CLI,-Google-Antigravity-or-Other-Agents-with-MCP.md","03_Wiki/concepts/skill-design-patterns.md"],"created_at":"2026-04-04","type":"summary"},"headers":[],"relativePath":"output/summaries/2026-04-04-skills-vs-mcp.md","filePath":"output/summaries/2026-04-04-skills-vs-mcp.md","lastUpdated":null}'),r={name:"output/summaries/2026-04-04-skills-vs-mcp.md"};function n(i,t,a,g,d,u){return e(),o("div",null,[...t[0]||(t[0]=[s('<h1 id="agent-skills-与-mcp-的区别对比研究" tabindex="-1">Agent Skills 与 MCP 的区别对比研究 <a class="header-anchor" href="#agent-skills-与-mcp-的区别对比研究" aria-label="Permalink to &quot;Agent Skills 与 MCP 的区别对比研究&quot;">​</a></h1><h2 id="tl-dr-一句话总结" tabindex="-1">TL;DR (一句话总结) <a class="header-anchor" href="#tl-dr-一句话总结" aria-label="Permalink to &quot;TL;DR (一句话总结)&quot;">​</a></h2><ul><li><strong>MCP (Model Context Protocol)</strong> 是 <strong>骨骼与肌肉（行动/数据层）</strong>：它为 Agent 提供标准化的外部工具调用接口（如查数据库、调 API）。</li><li><strong>Agent Skills (技能)</strong> 是 <strong>大脑与经验（知识/工作流层）</strong>：它按需为 Agent 注入领域知识、操作规范和固定的业务逻辑。</li></ul><p>两者是<strong>互补关系</strong>，MCP 提供能力，Skills 决定如何优雅地组合这些能力。</p><hr><h2 id="详细功能对比" tabindex="-1">详细功能对比 <a class="header-anchor" href="#详细功能对比" aria-label="Permalink to &quot;详细功能对比&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">维度</th><th style="text-align:left;">MCP (Model Context Protocol)</th><th style="text-align:left;">Agent Skills</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>核心定义</strong></td><td style="text-align:left;">开放的连接协议标准(&quot;AI界的USB-C&quot;)</td><td style="text-align:left;">动态加载的上下文和工作流封装</td></tr><tr><td style="text-align:left;"><strong>主要解决什么问题</strong></td><td style="text-align:left;">赋予大模型 <strong>行动力 (Action)</strong> 和 <strong>获取数据的能力</strong></td><td style="text-align:left;">赋予大模型 <strong>特定领域的知识 (Knowledge)</strong> 和流程规则</td></tr><tr><td style="text-align:left;"><strong>具体形式</strong></td><td style="text-align:left;">一个独立运行的 Server（通常独立于项目代码）</td><td style="text-align:left;">一组按需动态注入的指令文件（如 <code>SKILL.md</code>）</td></tr><tr><td style="text-align:left;"><strong>回答的问题</strong></td><td style="text-align:left;">&quot;如何调用数据库？如何调天气 API？&quot;</td><td style="text-align:left;">&quot;遇到旅游规划需求时，我该分几步走？什么该做？什么不该做？&quot;</td></tr><tr><td style="text-align:left;"><strong>扩展性</strong></td><td style="text-align:left;">&quot;即插即用&quot;：开发一个 MCP，任何客户端 (Antigravity, Gemini CLI) 均可使用</td><td style="text-align:left;">&quot;特定环境&quot;：根据当前工程的需要或特定框架（如 ADK）动态挂载</td></tr></tbody></table><h2 id="实战举例说明" tabindex="-1">实战举例说明 <a class="header-anchor" href="#实战举例说明" aria-label="Permalink to &quot;实战举例说明&quot;">​</a></h2><p>根据 Pavan Belagatti 的推文和 ADK 博客的设计原则，它们的协同工作如下：</p><p><strong>场景：用户要求 Agent &quot;规划一次去东京的 3 天旅程&quot;</strong></p><ol><li><strong>Agent Skills 发挥作用（规划与知识段）：</strong><ul><li>Agent 首先挂载 <code>travel-planner</code> Skill。</li><li>该 Skill 会给它注入<strong>经验</strong>：&quot;当用户问旅游时，你必须（1）先查当地天气，（2）根据天气挑选合适的室内外景点，（3）最后输出一个 Markdown 表格。&quot;</li></ul></li><li><strong>MCP 发挥作用（执行动作段）：</strong><ul><li>Agent 根据 Skill 的指导，需要查东京天气。它发现自己挂载了 <code>Weather-API-MCP</code>。</li><li>它通过 MCP 发起实际的 HTTP 请求，获取了真实的天气数据。</li></ul></li><li><strong>协同组合：</strong><ul><li>Agent 拿到 MCP 返回的天气数据后，再次参照 Skill 里的&quot;必须输出 Markdown 表格&quot;的指南，将结果呈现给用户。</li></ul></li></ol><h2 id="结论" tabindex="-1">结论 <a class="header-anchor" href="#结论" aria-label="Permalink to &quot;结论&quot;">​</a></h2><p>在构建先进的 AI 应用时，你不应该在 MCP 和 Skills 之间做&quot;二选一&quot;，而是应该<strong>同时使用它们</strong>。使用 MCP 让你的系统能够接入真实的外部世界，使用 Agent Skills 进行<strong>渐进式披露 (Progressive Disclosure)</strong>，让你庞大的业务逻辑可以在 Agent 需要时随时&quot;闪现&quot;在它的脑海中。</p>',13)])])}const k=l(r,[["render",n]]);export{h as __pageData,k as default};
